#include <bits/stdc++.h>
using namespace std;
int main()
{
    int a,b,e=0;
    cin>>a>>b;
    int c[a],d[a];
    for(int i=0;i<a;i++)
        {
            cin>>c[i]>>d[i];
            if(i!=0)
            {
                if(c[i]-d[i-1]>b)
                {
                    e+=c[i]-d[i-1]-b;
                }
            }
        }
    cout<<e;
    return 0;
}
